1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_TYPES = ["rune", "moonstone"];
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	type Item = { type: string; cursed?: boolean };
16	
17	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
18	
19	const mainItemPremium = (item: Item): number => {
20	  const base = basePremiumFor(item);
21	  return item.cursed ? base + base * CURSE_SURCHARGE_RATE : base;
22	};
23	
24	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
25	
26	const componentGroupPremium = (group: Item[]): number =>
27	  group.length === COMPONENT_BLOCK_SIZE
28	    ? COMPONENT_BLOCK_PREMIUM
29	    : group.reduce((sum, item) => sum + basePremiumFor(item), 0);
30	
31	const groupComponentsByType = (items: Item[]): Item[][] => {
32	  const groups: Record<string, Item[]> = {};
33	  for (const item of items) {
34	    (groups[item.type] ||= []).push(item);
35	  }
36	  return Object.values(groups);
37	};
38	
39	export function quote(_customer: { yearsWithMHPCO: number }, items: Item[]): number {
40	  const components = items.filter(isComponent);
41	  const mainItems = items.filter((item) => !isComponent(item));
42	  const mainTotal = mainItems.reduce((sum, item) => sum + mainItemPremium(item), 0);
43	  const componentTotal = groupComponentsByType(components).reduce(
44	    (sum, group) => sum + componentGroupPremium(group),
45	    0,
46	  );
47	  return mainTotal + componentTotal + PROCESSING_FEE;
48	}
49	
50	export function claim(): number {
51	  return undefined as unknown as number;
52	}
